import{_ as e,c as t,o as l,aN as s}from"./chunks/framework.BRm39z_l.js";const L=JSON.parse('{"title":"SQL优化","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/05.SQL优化.md","filePath":"mysql/05.SQL优化.md"}'),r={name:"mysql/05.SQL优化.md"};function o(n,a,i,S,_,c){return l(),t("div",null,a[0]||(a[0]=[s('<h1 id="sql优化" tabindex="-1">SQL优化 <a class="header-anchor" href="#sql优化" aria-label="Permalink to &quot;SQL优化&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#什么是慢-sql">什么是慢 SQL</a></li><li><a href="#如何优化慢-sql">如何优化慢 SQL</a></li></ul></nav><h2 id="什么是慢-sql" tabindex="-1">什么是慢 SQL <a class="header-anchor" href="#什么是慢-sql" aria-label="Permalink to &quot;什么是慢 SQL&quot;">​</a></h2><p>MySQL 中有一个叫 long_query_time 的参数，原则上执行时间超过该参数值的 SQL 就是慢 SQL，会被记录到慢查询日志中</p><h2 id="如何优化慢-sql" tabindex="-1">如何优化慢 SQL <a class="header-anchor" href="#如何优化慢-sql" aria-label="Permalink to &quot;如何优化慢 SQL&quot;">​</a></h2><p>首先，需要找到那些比较慢的 SQL，可以通过启用慢查询日志，记录那些超过指定执行时间的 SQL 查询。</p><p>也可以使用 <code>show processlist;</code> 命令查看当前正在执行的 SQL 语句，找出执行时间较长的 SQL。</p><p>或者在业务基建中加入对慢 SQL 的监控，常见的方案有字节码插桩、连接池扩展、ORM 框架扩展等。</p><p>然后，使用 EXPLAIN 查看慢 SQL 的执行计划，看看有没有用索引，大部分情况下，慢 SQL 的原因都是因为没有用到索引。</p><p>最后，根据分析结果，通过添加索引、优化查询条件、减少返回字段等方式进行优化</p>',10)]))}const Q=e(r,[["render",o]]);export{L as __pageData,Q as default};
